import { Component, OnInit } from '@angular/core';
import { CategoryService } from '../services/category.service';
import { Category } from '../models/category.model';
import { Observable } from 'rxjs';
import { Router } from '@angular/router';
import Swal from 'sweetalert2';


@Component({
  selector: 'app-categories-list',
  templateUrl: './categories-list.component.html',
  styleUrls: ['./categories-list.component.css']
})
export class CategoriesListComponent  implements OnInit {

  categories$?: Observable<Category[]>
  id:string | null = null

  constructor(private categoryService: CategoryService, private router: Router){

  }
  ngOnInit(): void {
    this.categories$ = this.categoryService.getAllCategories()

  }

  onDelete(id: string): void {
    Swal.fire({
      title: "Are you sure?",
      text: "this action cannot be undone!",
      icon: "warning",
      showCancelButton: true,
      confirmButtonColor: "#d33",
      cancelButtonColor: "#3085d6",
      confirmButtonText: "yes, delete!",
      cancelButtonText: "Cancel"
    }).then((result) => {
      if (result.isConfirmed) {
        this.categoryService.deleteCategory(id).subscribe({
          next: () => {
            Swal.fire("Deleted!", "category removed.", "success");
            this.categories$ = this.categoryService.getAllCategories();
          },
          error: (err) => {
            console.error("error ecluding category:", err);
            Swal.fire("Erro!", "a problem occured when deleting category.", "error");
          }
        });
      }
    });
  }


}
<div class="container mt-4">
    <h1 class="text-center mb-4">📂 Lista de Categorias</h1>

    <div class="d-flex justify-content-between align-items-center mb-3">
        <span class="fw-light text-muted">Gerencie as categorias cadastradas</span>
        <a class="btn btn-primary btn-sm px-3" [routerLink]="['/admin/categories/add']">
            ➕ Adicionar Categoria
        </a>
    </div>

    <!-- Exibe mensagem de erro caso ocorra -->
    <div *ngIf="errorMessage" class="alert alert-danger text-center">
        {{ errorMessage }}
    </div>

    <!-- Loader enquanto carrega -->
    <div *ngIf="isLoading" class="text-center my-5">
        <div class="spinner-border text-primary" role="status"></div>
        <p class="mt-2">Carregando categorias...</p>
    </div>

    <!-- Exibe a tabela somente se houver categorias e não estiver carregando -->
    <table *ngIf="!isLoading && categories.length > 0" class="table table-hover table-striped shadow-sm rounded">
        <thead class="table-dark">
            <tr>
                <th class="text-center">#</th>
                <th>Nome</th>
                <th>URL Handle</th>
                <th class="text-center">Ações</th>
            </tr>
        </thead>
        <tbody>
            <tr *ngFor="let category of categories">
                <td class="text-center">{{category.id}}</td>
                <td>{{category.name}}</td>
                <td>{{category.urlHandle}}</td>
                <td class="d-flex justify-content-center">
                    <a class="btn btn-outline-primary btn-sm me-2" [routerLink]="['/admin/categories', category.id]">
                        ✏️ Editar
                    </a>
                    <button type="button" class="btn btn-outline-danger btn-sm" (click)="onDelete(category.id)">
                        🗑️ Excluir
                    </button>
                </td>
            </tr>
        </tbody>
    </table>

    <!-- Mensagem caso não tenha categorias -->
    <div *ngIf="!isLoading && categories.length === 0" class="alert alert-warning text-center mt-3">
        Nenhuma categoria cadastrada.
    </div>
</div>
